patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -10,7 +10,7 @@
   output logic [15:0] data_out
 );

-  always @(sel) begin
+  always @(sel or in0 or in1 or in2 or in3) begin
     case(sel)
       2'b00: data_out = in0;
       2'b01: data_out = in1;

before_code:
module mux_4to1_16bit (
  input logic [15:0] in0,
  input logic [15:0] in1,
  input logic [15:0] in2,
  input logic [15:0] in3,
  input logic [1:0] sel,
  output logic [15:0] data_out
);

  always @(sel) begin
    case(sel)
      2'b00: data_out = in0;
      2'b01: data_out = in1;
      2'b10: data_out = in2;
      2'b11: data_out = in3;
      default: data_out = 16'b0;
    endcase
  end

endmodule

after_code:
module mux_4to1_16bit (
  input logic [15:0] in0,
  input logic [15:0] in1,
  input logic [15:0] in2,
  input logic [15:0] in3,
  input logic [1:0] sel,
  output logic [15:0] data_out
);

  always @(sel or in0 or in1 or in2 or in3) begin
    case(sel)
      2'b00: data_out = in0;
      2'b01: data_out = in1;
      2'b10: data_out = in2;
      2'b11: data_out = in3;
      default: data_out = 16'b0;
    endcase
  end

endmodule
